package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSet() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = CSVFormat.newFormat(',').withQuote('"').withCommentMarker('#').withEscape('\\')
                .withIgnoreSurroundingSpaces(true).withIgnoreEmptyLines(false).withRecordSeparator("\r\n")
                .withNullString("\\N").withHeader((String[]) null).withHeaderComments((Object[]) null).withSkipHeaderRecord(false)
                .withAllowMissingColumnNames(false).withIgnoreHeaderCase(false).withTrim(false).withTrailingDelimiter(false);

        // When
        Method method = CSVFormat.class.getDeclaredMethod("isCommentMarkerSet");
        method.setAccessible(true);
        boolean result = (boolean) method.invoke(csvFormat);

        // Then
        assertTrue(result);

        // Additional assertion to cover the null case
        CSVFormat csvFormatWithoutCommentMarker = CSVFormat.newFormat(',').withQuote('"').withCommentMarker(null)
                .withEscape('\\').withIgnoreSurroundingSpaces(true).withIgnoreEmptyLines(false).withRecordSeparator("\r\n")
                .withNullString("\\N").withHeader((String[]) null).withHeaderComments((Object[]) null).withSkipHeaderRecord(false)
                .withAllowMissingColumnNames(false).withIgnoreHeaderCase(false).withTrim(false).withTrailingDelimiter(false);
        Method methodWithoutCommentMarker = CSVFormat.class.getDeclaredMethod("isCommentMarkerSet");
        methodWithoutCommentMarker.setAccessible(true);
        boolean resultWithoutCommentMarker = (boolean) methodWithoutCommentMarker.invoke(csvFormatWithoutCommentMarker);
        assertFalse(resultWithoutCommentMarker);
    }
}
